export function RangeControlled() {
  const [value, setValue] = useState<[string | null, string | null]>([
    '2022-04-11 14:30:00',
    '2022-04-15 16:00:00',
  ]);
  return (
    <div style={{ padding: 40, maxWidth: 400 }}>
      <InlineDateTimePicker type="range" value={value} onChange={setValue} />
      <Group mt="xl">
        <Button onClick={() => setValue([null, null])}>Clear</Button>
      </Group>
    </div>
  );
}

export function Range() {
  return (
    <Wrapper
      getDayProps={(date) => ({
        selected:
          dayjs(date).isSame('2022-04-09', 'date') || dayjs(date).isSame('2022-04-15', 'date'),
        firstInRange: dayjs(date).isSame('2022-04-09', 'date'),
        inRange:
          dayjs(date).isAfter('2022-04-09', 'date') && dayjs(date).isBefore('2022-04-15', 'date'),
        lastInRange: dayjs(date).isSame('2022-04-15', 'date'),
      })}
    />
  );
}

